83	async function getCachedMerchGroup(sql) {
84	  const now = Date.now();
85	  if (merchGroupCache.rows && merchGroupCache.expiresAt > now) {
86	    return merchGroupCache.rows;
87	  }
88	  const rows = await sql.merchGroup.findAll({
89	    attributes: ['mg_id', 'mg_code', 'mg_desc'],
90	  });
91	  merchGroupCache = { rows, expiresAt: now + CACHE_TTL_MS };
92	  return rows;
93	}
