4115	/**
4116	 * Set which custom view is default for this user+grid, or clear all (fall back to global Default).
4117	 * Body: { grid_id, view_name } to set, or { grid_id, clear: true } to clear.
4118	 */
4119	Customer.setGridDefaultView = async (req, result) => {
4120	  try {
4121	    let user_info = await getUserInfo(req.headers.authorization);
4122	    let userDetail = await findUserInfoWithEmail(user_info);
4123	
4124	    if (!userDetail && user_info.role === 'vendor') {
4125	      userDetail = await findVendorInfoWithEmail(user_info);
4126	      if (userDetail) userDetail.id = userDetail.vendor_id;
4127	    }
4128	
4129	    const userId = userDetail?.id || null;
4130	    const { grid_id, view_name, clear } = req.body;
4131	
4132	    if (!grid_id) {
4133	      return result({ message: 'grid_id is required.' }, null);
4134	    }
4135	    if (userId == null) {
4136	      return result({ message: 'User not found.' }, null);
4137	    }
4138	
4139	    await sql.GridViewState.update(
4140	      { is_default: false, updated_at: new Date() },
4141	      {
4142	        where: {
4143	          user_id_fk: userId,
4144	          grid_id: grid_id
4145	        },
4146	        individualHooks: true
4147	      }
4148	    );
4149	
4150	    if (clear === true || clear === 'true') {
4151	      return result(null, { success: true });
4152	    }
4153	
4154	    if (!view_name || typeof view_name !== 'string') {
4155	      return result({ message: 'view_name is required unless clear is true.' }, null);
4156	    }
4157	
4158	    const trimmed = view_name.trim();
4159	    if (trimmed === 'Default') {
4160	      return result({ message: 'Cannot set Default as a custom default; use clear default instead.' }, null);
4161	    }
4162	
4163	    const row = await sql.GridViewState.findOne({
4164	      where: {
4165	        user_id_fk: userId,
4166	        grid_id: grid_id,
4167	        view_name: trimmed
4168	      }
4169	    });
4170	
4171	    if (!row) {
4172	      return result({ message: 'View not found for this user.' }, null);
4173	    }
4174	
4175	    await sql.GridViewState.update(
4176	      { is_default: true, updated_at: new Date() },
4177	      {
4178	        where: {
4179	          user_id_fk: userId,
4180	          grid_id: grid_id,
4181	          view_name: trimmed
4182	        },
4183	        individualHooks: true
4184	      }
4185	    );
