4331	/**
4332	 * Translate a Sequelize/upload error into a short bilingual reason string
4333	 * suitable for showing directly to a factory user.
4334	 *
4335	 * The full technical error is always logged server-side; this function only
4336	 * produces the human-readable portion that goes in the API response.
4337	 */
4338	function describeImportRowError(err, row) {
4339	  const name = err.name || '';
4340	  const msg  = (err.message || '').toLowerCase();
4341	
4342	  // ── Sequelize constraint / validation errors ───────────────────────────
4343	  if (name === 'SequelizeUniqueConstraintError') {
4344	    const field = err.errors?.[0]?.path || '';
4345	    return field
4346	      ? `Duplicate value in "${field}" · "${field}"字段值重复`
4347	      : 'Duplicate record · 记录重复';
4348	  }
4349	
4350	  if (name === 'SequelizeForeignKeyConstraintError') {
4351	    // All FK values in this import (customer, step, factory) are either
4352	    // system-provided or resolved before the DB call — a constraint error here
4353	    // is a system problem, not a factory data problem.
4354	    return 'System reference error — please contact support · 系统引用错误，请联系客服';
4355	  }
4356	
4357	  if (name === 'SequelizeValidationError') {
4358	    const fields = (err.errors || []).map(e => e.path).filter(Boolean);
4359	    if (fields.length) {
4360	      return `Invalid value in: ${fields.join(', ')} · 字段值无效：${fields.join('、')}`;
4361	    }
4362	    return 'Validation failed · 数据验证失败';
4363	  }
4364	
4365	  if (name === 'SequelizeDatabaseError') {
4366	    if (msg.includes('null value') || msg.includes('not-null')) {
4367	      // Extract column name from Postgres error if present
4368	      const colMatch = err.message.match(/column "([^"]+)"/);
4369	      const col = colMatch ? colMatch[1] : '';
4370	      return col
4371	        ? `Required field missing: ${col} · 必填字段为空：${col}`
4372	        : 'Required field is empty · 必填字段为空';
4373	    }
4374	    if (msg.includes('value too long') || msg.includes('character varying')) {
4375	      return 'A value is too long for its field · 某字段内容超出长度限制';
4376	    }
4377	    if (msg.includes('invalid input syntax')) {
4378	      const typeMatch = err.message.match(/type "([^"]+)"/);
4379	      const type = typeMatch ? typeMatch[1] : 'field';
4380	      return `Invalid format for ${type} (expected a number?) · ${type}格式无效（是否应为数字？）`;
4381	    }
4382	    return 'Database error · 数据库错误';
4383	  }
4384	
4385	  // ── Network / storage errors ───────────────────────────────────────────
4386	  if (msg.includes('econnrefused') || msg.includes('enotfound') || msg.includes('etimedout')) {
4387	    return 'Network error — please try again · 网络错误，请重试';
4388	  }
4389	
4390	  // ── Fallback: first 80 chars of the raw message, still bilingual label ─
4391	  const short = (err.message || 'unknown error').slice(0, 80);
4392	  return `${short} · 导入失败`;
4393	}
