4395	/**
4396	 * POST /importFactoryRFQ   (multipart/form-data, field: "file")
4397	 *
4398	 * Parses a completed factory offer xlsx and creates:
4399	 *   1. One RFQGroup named by the factory (req.body.groupName)
4400	 *   2. One RFQItem per data row  (price code: foff-XXXX, step: @factories)
4401	 *   3. One RFQVendor quote record per item (linked to the uploading factory)
4402	 *   4. Images embedded in xlsx cells are uploaded to DigitalOcean Spaces
4403	 *
4404	 * Returns a summary: { created, items, errors, groupId, groupName }
4405	 */
4406	Customer.importFactoryRFQ = async (req, result) => {
4407	  const { getUserInfo } = require('../helpers/auth');
4408	  const { parseImport, getNextFoffPriceCodes } = require('../helpers/rfqBulkImport');
4409	  const { uploadBufferToSpaces } = require('../helpers/digitalocean');
4410	
4411	  try {
4412	    const token = req.headers.authorization;
4413	    const userInfo = await getUserInfo(token);
4414	    const factoryId = userInfo ? userInfo.factory_id : null;
4415	
4416	    const groupName = (req.body.groupName || '').trim() || 'Factory Upload';
4417	    if (!req.file || !req.file.buffer) {
4418	      return result(null, { created: 0, errors: ['No file received · 未收到文件'] });
4419	    }
4420	
4421	    // Parse the uploaded xlsx — catch format errors cleanly so they reach the
4422	    // user as a readable message instead of a 500.
4423	    let rows, images;
4424	    try {
4425	      ({ rows, images } = await parseImport(req.file.buffer));
4426	    } catch (parseErr) {
4427	      console.warn('importFactoryRFQ: parse error:', parseErr.message);
4428	      return result(null, {
4429	        created: 0,
4430	        errors: ['Invalid file format — please use the official template · 文件格式不正确，请使用官方模板'],
4431	      });
4432	    }
4433	
4434	    if (rows.length === 0) {
4435	      return result(null, { created: 0, errors: ['No data rows found · 未找到数据行，请至少填写一行'] });
4436	    }
4437	
4438	    // Build customer lookup map (name → id, case-insensitive)
4439	    const allCustomers = await sql.customers.findAll({
4440	      attributes: ['customers_id', 'customers_name'],
4441	      raw: true,
4442	    });
4443	    const customerMap = {};
4444	    allCustomers.forEach(c => {
4445	      if (c.customers_name) customerMap[c.customers_name.toLowerCase().trim()] = c.customers_id;
4446	    });
4447	
4448	    // Resolve @factories step ID
4449	    const factoriesStep = await sql.RFQStep.findOne({ where: { RFQStep_title: '@factories' } });
4450	    const stepId = factoriesStep ? factoriesStep.RFQStep_id : 3;
4451	
4452	    // Allocate price codes for all rows upfront (atomic sequence)
4453	    const priceCodes = await getNextFoffPriceCodes(sql, rows.length, Op);
4454	
4455	    // Create the RFQ Group
4456	    const group = await sql.RFQGroup.create({
4457	      RFQGroup_name: groupName,
4458	      IsLegacy: false,
4459	      user_id_fk: null,
4460	    });
4461	    const groupId = group.dataValues.RFQGroup_id;
4462	
4463	    const created = [];
4464	    const errors = [];
4465	
4466	    for (let i = 0; i < rows.length; i++) {
4467	      const row = rows[i];
4468	      try {
4469	        // Best-effort lookup — if the factory's dropdown value doesn't match
4470	        // (e.g. template was stale), we store null rather than failing the row.
4471	        const customerId = customerMap[(row.customer || '').toLowerCase().trim()] || null;
4472	
4473	        // Upload image if the factory embedded one in this row
4474	        let pictureFull = null;
4475	        let pictureThumb = null;
4476	        if (images[row._rowNumber]) {
4477	          const { buffer: imgBuf, extension } = images[row._rowNumber];
4478	          const ts = Date.now() + i; // unique per row
4479	          const ext = (extension || 'jpeg').replace(/^\./, '');
4480	          const contentType = ext === 'png' ? 'image/png' : 'image/jpeg';
4481	          const imgKey = `images-${ts}-foff-offer.${ext}`;
4482	          try {
4483	            pictureFull = await uploadBufferToSpaces(imgBuf, imgKey, contentType);
4484	            pictureThumb = pictureFull; // same file; thumbnail resizing can be added later
4485	          } catch (imgUploadErr) {
4486	            console.warn(`importFactoryRFQ: image upload failed for row ${i + 1}:`, imgUploadErr.message);
4487	          }
4488	        }
4489	
4490	        // Create RFQItem
4491	        const item = await sql.RFQItem.create({
4492	          rfqItem_style_number:    priceCodes[i],
4493	          rfqItem_description:     row.description,
4494	          rfqItem_customer:        customerId,
4495	          rfqItem_quantity:        row.quantity != null ? String(row.quantity) : null,
4496	          rfqItem_case_pack:       row.case_pack != null ? String(row.case_pack) : null,
4497	          rfqItem_picture:         pictureFull,
4498	          rfqItem_picturethumb:    pictureThumb,
4499	          rfqItem_rfq_group:       groupId,
4500	          rfqItem_step:            stepId,
4501	          rfqItem_choosen_vendor:  factoryId,
4502	          rfqItem_divCode_id_fk:   FACTORY_IMPORT_DEFAULT_DIVISION,
4503	          rfqItem_active:          FACTORY_IMPORT_DEFAULT_STATUS_ID,
4504	          rfqItem_factories_step_at: new Date().toISOString(),
4505	          rfqItem_notes:           row.notes || null,
4506	        });
4507	        const itemId = item.dataValues.rfqItem_id;
4508	
4509	        // Calculate CBM/pc from carton dimensions
4510	        let cbmPc = null;
4511	        const l = parseFloat(row.carton_length);
