4534	          req_status:        2, // 2 = quoted
4535	        });
4536	
4537	        created.push({ priceCode: priceCodes[i], description: row.description });
4538	      } catch (rowErr) {
4539	        console.error(`importFactoryRFQ row ${i + 1} error:`, rowErr);
